// models/Document.js
const mongoose = require('mongoose');
const { Schema } = mongoose;

const documentSchema = new Schema({
  title:       { type: String, required: true },
  body:        { type: String },
  companyId:   { type: Schema.Types.ObjectId, ref: 'Company', required: true, index: true },
  createdBy:   { type: Schema.Types.ObjectId, ref: 'User', required: true },
  createdAt:   { type: Date, default: Date.now }
});

module.exports = mongoose.model('Document', documentSchema);


// routes/documents.js
const express  = require('express');
const router   = express.Router();
const Document = require('../models/Document');

const asyncWrap = fn => (req, res, next) => Promise.resolve(fn(req, res, next)).catch(next);

// GET /api/documents          -> list all documents for the user's company
// GET /api/documents/:id      -> view a single document (company-scoped)
router.get(
  '/',
  asyncWrap(async (req, res) => {
    const docs = await Document.find({ companyId: req.user.companyId }).lean();
    res.json(docs);
  })
);

router.get(
  '/:id',
  asyncWrap(async (req, res) => {
    const doc = await Document.findOne({
      _id: req.params.id,
      companyId: req.user.companyId
    }).lean();

    if (!doc) return res.status(404).json({ message: 'Document not found' });
    res.json(doc);
  })
);

module.exports = router;


// app.js
